const items = $input.all();
const results = [];

for (const item of items) {
  const clientId = item.json.id;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);

  const dateStr = yesterday.toISOString().split('T')[0];

  // Fetch leads created yesterday for this client
  const leadsResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/lead_interactions?client_id=eq.${clientId}&created_at=gte.${yesterday.toISOString()}&created_at=lt.${today.toISOString()}&select=id,score,source`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`
    }
  });

  // Fetch agent activity yesterday
  const activityResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://bfzdcyuyilesubtgbhdc.supabase.co/rest/v1/agent_activity?client_id=eq.${clientId}&created_at=gte.${yesterday.toISOString()}&created_at=lt.${today.toISOString()}&select=id,agent_name,action`,
    headers: {
      'apikey': $env.SUPABASE_API_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_API_KEY}`
    }
  });

  const leads = leadsResponse || [];
  const activities = activityResponse || [];

  const newLeads = leads.length;
  const hotLeads = leads.filter(l => l.score >= 80).length;
  const avgScore = leads.length > 0 
    ? Math.round(leads.reduce((sum, l) => sum + (l.score || 0), 0) / leads.length) 
    : 0;
  const agentActions = activities.length;

  results.push({
    json: {
      client_id: clientId,
      date: dateStr,
      new_leads: newLeads,
      hot_leads: hotLeads,
      avg_lead_score: avgScore,
      agent_actions: agentActions,
      total_conversations: 0,
      ad_spend: 0,
      ad_impressions: 0,
      ad_clicks: 0
    }
  });
}

return results;
